import requests

def fetch_digilocker_document(access_token, document_id):
    url = f"https://api.digilocker.gov.in/public/document/{document_id}"
    headers = {
        "Authorization": f"Bearer {access_token}
    }
    response = requests.get(url, headers=headers)
    if response.status_code == 200:
        return response.json()
    else:
        raise Exception("Failed to fetch document")

This Python function uses the DigiLocker API to retrieve a document by its ID, requiring an access token for authentication.
